function i(n){return n instanceof Date?n.getTime():typeof n=="number"?n:Date.parse(n)}function u(n,t){if(n==null||n==="")return"·";const e=i(n);if(!Number.isFinite(e))return"·";const r=Math.max(0,Math.round((t-e)/1e3));return r<5?"now":r<60?`${r}s`:r<3600?`${Math.round(r/60)}m`:r<86400?`${Math.round(r/3600)}h`:`${Math.round(r/86400)}d`}function a(n){if(n==null||n==="")return"·";const t=i(n);if(!Number.isFinite(t))return"·";const e=new Date(t),r=String(e.getHours()).padStart(2,"0"),o=String(e.getMinutes()).padStart(2,"0");return`${r}:${o}`}function f(n){if(n==null||n==="")return"·";const t=i(n);return Number.isFinite(t)?new Date(t).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}):"·"}export{f as a,a as b,u as f};
